const customerItems = $items("Load Customer Data (Customer_Master)", 0);
const historyItems = $items("Load Campaign Decision History", 0);

const historyMap = new Map();

for (const item of historyItems) {
  const row = item.json;
  const customerId = row.Customer_ID;
  if (!customerId) continue;

  if (!historyMap.has(customerId)) {
    historyMap.set(customerId, []);
  }

  historyMap.get(customerId).push(row);
}

function toTimestamp(value) {
  if (!value) return 0;
  const t = new Date(value).getTime();
  return Number.isNaN(t) ? 0 : t;
}

function getLatestRecord(records) {
  if (!records || records.length === 0) return null;

  return records
    .slice()
    .sort((a, b) => {
      const aTime = toTimestamp(a.Decision_Time);
      const bTime = toTimestamp(b.Decision_Time);
      return bTime - aTime;
    })[0];
}

return customerItems.map((item) => {
  const customer = item.json;
  const customerId = customer.Customer_ID;
  const historyRecords = historyMap.get(customerId) || [];
  const latest = getLatestRecord(historyRecords);

  return {
    json: {
      ...customer,
      feedback_context: latest
        ? {
            has_feedback: true,
            previous_campaign_priority: latest.Campaign_Priority || null,
            previous_recommended_action: latest.Recommended_Action || null,
            previous_decision_time: latest.Decision_Time || null,
            previous_decision_status: latest.Decision_Status || null,
            previous_notes: latest.Notes || null,
            feedback_count: historyRecords.length,
          }
        : {
            has_feedback: false,
            previous_campaign_priority: null,
            previous_recommended_action: null,
            previous_decision_time: null,
            previous_decision_status: null,
            previous_notes: null,
            feedback_count: 0,
          },
    },
  };
});
